<?php
namespace App\Http\Controllers\Api\Owner;
use App\Http\Controllers\Controller; use App\Models\SupplyOrder; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request;
class SupplyOrderController extends Controller {
  public function index(Request $r): JsonResponse { return response()->json(SupplyOrder::with(['supplier:id,name','approver:id,name'])->where('shop_id',$r->user()->shop_id)->latest('id')->get()); }
  public function store(Request $r): JsonResponse { $v=$r->validate(['supplier_id'=>'required|integer|exists:suppliers,id','po_number'=>'nullable|string|max:100','materials_json'=>'nullable|array','quantity_total'=>'nullable|numeric|min:0','total_cost'=>'nullable|numeric|min:0','ordered_at'=>'nullable|date','expected_arrival_at'=>'nullable|date','received_at'=>'nullable|date','status'=>'nullable|string|max:50','notes'=>'nullable|string']); $m=SupplyOrder::create(array_merge($v,['shop_id'=>$r->user()->shop_id,'po_number'=>$v['po_number']??('PO-'.now()->format('Ymd-His')),'status'=>$v['status']??'draft','approved_by'=>$r->user()->id])); return response()->json($m->load(['supplier:id,name','approver:id,name']),201);} 
  public function update(Request $r,SupplyOrder $supplyOrder): JsonResponse { abort_unless($supplyOrder->shop_id===$r->user()->shop_id,403); $v=$r->validate(['supplier_id'=>'nullable|integer|exists:suppliers,id','po_number'=>'nullable|string|max:100','materials_json'=>'nullable|array','quantity_total'=>'nullable|numeric|min:0','total_cost'=>'nullable|numeric|min:0','ordered_at'=>'nullable|date','expected_arrival_at'=>'nullable|date','received_at'=>'nullable|date','status'=>'nullable|string|max:50','notes'=>'nullable|string']); $supplyOrder->update($v); return response()->json($supplyOrder->fresh()->load(['supplier:id,name','approver:id,name'])); }
}
